class Solution {
    public long minimumCost(String s) {
        int n = s.length();
        long total = 0;
        for (int i = 0; i < n - 1; i++) {
            if (s.charAt(i) != s.charAt(i + 1)) {
                int cost1 = i + 1;
                int cost2 = n - (i + 1);
                total += Math.min(cost1, cost2);
            }
        }
        return total;
    }
}

